**JavaScript (canvas-drawing.js):**

```javascript
// Assume 'commandsString' is our encoded drawing commands.
// For simplicity, it follows the format "Mx,y" to move to (x, y), and "Lx,y" to line to (x, y).
let commandsString = "M10,10L100,100L200,50";

// Parse the commands into a format that the canvas can understand.
function parseCommands(commandsStr) {
    let commands = commandsStr.match(/[ML]\d+,\d+/g);
    let parsedCommands = commands.map(cmd => {
        let [action, ...points] = cmd.split(/(?=[ML])/);
        let [x, y] = points[0].slice(1).split(',').map(Number);
        return { action, x, y };
    });
    return parsedCommands;
}

// Draw on the canvas with the parsed commands.
function drawOnCanvas(parsedCommands) {
    let canvas = document.getElementById('myCanvas');
    let ctx = canvas.getContext('2d');

    ctx.beginPath();
    parsedCommands.forEach(cmd => {
        if (cmd.action === 'M') {
            ctx.moveTo(cmd.x, cmd.y);
        } else if (cmd.action === 'L') {
            ctx.lineTo(cmd.x, cmd.y);
        }
    });
    ctx.stroke();
}

// Use our functions to parse the string and draw the representation.
let parsedCommands = parseCommands(commandsString);
drawOnCanvas(parsedCommands);
```

In this example, when you load your HTML page with this script (canvas-drawing.js) included, it will parse a hardcoded string of drawing commands (`commandsString`) and draw the corresponding lines on the canvas.

