      function draw() {
        const canvas = document.getElementById('myCanvas');
        const ctx = canvas.getContext('2d');
        const commands = document.getElementById('drawingCommands').value;

        // Clear the canvas before drawing
        ctx.clearRect(0, 0, canvas.width, canvas.height);

        // Default color is black
        ctx.strokeStyle = 'black';
        ctx.fillStyle = 'black';

        // Begin a new path for drawing
        ctx.beginPath();

        // Split the commands by space and iterate over them
        commands.split(' ').forEach(command => {
          const [cmd, ...args] = command.split(',');

          switch (cmd) {
            case 'C': // Set color
              ctx.strokeStyle = args[0];
              ctx.fillStyle = args[0];
              break;
            case 'M': // Move to (without drawing)
              ctx.moveTo(...args.map(Number));
              break;
            case 'L': // Line to
              ctx.lineTo(...args.map(Number));
              break;
            case 'F': // Fill the current path
              ctx.fill();
              break;
          }
        });

        // Stroke the path with the current stroke color
        ctx.stroke();
      }
