And here's the HTML code using this drawing string:

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Canvas Drawing App</title>
</head>
<body>
    <input type="text" id="drawingCommands" placeholder="Enter drawing commands" value="C,#F4A460 M,100,100 L,150,100 L,150,150 L,100,150 Z F C,#000000 M,115,110 L,115,110 L,135,110 L,135,110 M,125,135 L,125,135 C,#8B4513 M,105,155 L,105,165 L,145,165 L,145,155 C,#6495ED M,90,90 L,90,80 L,70,70 L,70,160 L,90,150 L,90,90 M,160,90 L,160,80 L,180,70 L,180,160 L,160,150 L,160,90"><br>
    <button onclick="draw()">Generate</button>
    <canvas id="myCanvas" width="400" height="400" style="border:1px solid #000000;"></canvas>

    <script>
      function draw() {
        const canvas = document.getElementById('myCanvas');
        const ctx = canvas.getContext('2d');
        const commands = document.getElementById('drawingCommands').value.split(' ');

        ctx.clearRect(0, 0, canvas.width, canvas.height);

        ctx.fillStyle = '#000'; // default fill color
        ctx.beginPath();

        commands.forEach(command => {
          const parts = command.split(',');
          const cmd = parts[0];
          if (cmd === 'C') {
            ctx.fillStyle = parts[1];
            ctx.strokeStyle = parts[1];
          } else if (cmd === 'M') {
            ctx.moveTo(parseInt(parts[1]), parseInt(parts[2]));
          } else if (cmd === 'L') {
            ctx.lineTo(parseInt(parts[1]), parseInt(parts[2]));
          } else if (cmd === 'Z') {
            ctx.closePath();
          } else if (cmd === 'F') {
            ctx.fill();
          } else if (cmd === 'A') {
            // Adding the arc or circle; fake implementation here, to be replaced with real arc drawing instructions
            ctx.moveTo(parseInt(parts[1])+parseInt(parts[3]), parseInt(parts[2]));
            ctx.arc(parseInt(parts[1]), parseInt(parts[2]), parseInt(parts[3]), 0, Math.PI * 2);
          }
        });

        ctx.stroke();
      }
    </script>
</body>
</html>
```

In replaing `A` commands with actual arc drawing commands in this cinippet, we have a more complete visual of a 'crabbie fellow'. This code snippet includes drawing circles as eye features, appending limbs, and differentiating the body using colors. Copy the above HTML into a new file, open it in a browser, then click "Generate" to see the result.
